def terminate(self, termination_date: date | None = None) -> None:
    if self.employment_status == EmploymentStatus.TERMINATED:
        raise InvalidEmployeeOperationError("Employee is already terminated")
    self.employment_status = EmploymentStatus.TERMINATED
    self.termination_date = termination_date or date.today()

def suspend(self) -> None:
    if self.employment_status != EmploymentStatus.ACTIVE:
        raise InvalidEmployeeOperationError("Cannot suspend — not ACTIVE")
    self.employment_status = EmploymentStatus.SUSPENDED

def promote(self, new_position: str, new_salary: Decimal, new_role=None) -> None:
    if self.employment_status == EmploymentStatus.TERMINATED:
        raise InvalidEmployeeOperationError("Cannot promote terminated employee")
    self.position = new_position
    self.salary = new_salary

async def execute(self, command: HireEmployeeCommand) -> Employee:
    existing = await self._repository.get_by_email(command.email)
    if existing:
        raise EmployeeAlreadyExistsError(command.email)
    employee = Employee.create({...})
    return await self._repository.create(employee)

def approve(self, reviewer_id: int, comment: str | None = None) -> None:
