class Payment(AggregateRoot):
    id: PaymentId
    user_id: UserId
    amount: Money
    status: PaymentStatus

    def complete(self, transaction_reference=None):
        if not self.can_be_completed():
            raise PaymentAlreadyProcessedException(...)
        self.status = PaymentStatus.COMPLETED
        self.completed_at = datetime.now(timezone.utc)
        self._add_event(PaymentCompleted(...))

    def refund(self, amount: Money, reason: str):
        if not self.can_be_refunded():
            raise PaymentNotRefundableException(...)
        self._add_event(PaymentRefunded(...))

class KafkaPaymentEventsPublisher(PaymentEventsPublisher):
    async def publish(self, event_name, payload, key=None):
        message = {
            "event_type": event_name,
            "service": settings.SERVICE_NAME,
            "payload": payload,
        }
        value = json.dumps(message, default=str).encode("utf-8")
        self._producer.send(topic=self._topic, key=key, value=value)

